import React, { useState } from "react";
import { Link } from "react-router-dom"; // This is for routing to the full page.
import "../styles/News.css";

const newsData = [
  {
    id: 1,
    img: "/images/1.jpg",
    title: "Legal Insights on Intellectual Property",
    description:
      "Stay updated with the latest trends and challenges in intellectual property law. A deep dive into the current challenges businesses face in protecting their IP.",
    fullDescription:
      "In this article, we discuss the complexities of intellectual property law, including the most common pitfalls, how businesses can safeguard their IP, and the potential legal issues they might face when dealing with international IP laws.",
  },
  {
    id: 2,
    img: "/images/news2.jpg",
    title: "Bankruptcy Law and Its Impact on Corporations",
    description:
      "How does bankruptcy law affect the financial stability of businesses? Read about the legal procedures and implications for corporations during bankruptcy.",
    fullDescription:
      "Bankruptcy law is designed to protect creditors and ensure that debts are paid, but it also has significant impacts on corporations and their employees. We will explore the legal procedures and how companies can navigate this challenging situation.",
  },
  {
    id: 3,
    img: "/images/news3.jpg",
    title: "Corporate Mergers: Legal Framework and Challenges",
    description:
      "Mergers and acquisitions are complex processes. In this article, we outline the legal frameworks involved and highlight some of the challenges businesses face during mergers.",
    fullDescription:
      "Mergers and acquisitions (M&A) can be a growth strategy for many businesses, but they come with significant legal hurdles. From regulatory approvals to contractual obligations, this article covers the essential aspects businesses need to consider when undertaking M&A activities.",
  },
];

const News = () => {
  const [showMore, setShowMore] = useState(false);

  const handleShowMore = () => {
    setShowMore(true);
  };

  return (
    <div className="news-container">
      <h2 className="news-title">News & Articles</h2>
      <p className="news-subtitle">Stay updated with the latest legal news and insights.</p>

      <div className="news-preview">
        {newsData.slice(0, 3).map((news) => (
          <div key={news.id} className="news-card">
            <img src={news.img} alt={news.title} />
            <div className="news-card-content">
              <h3>{news.title}</h3>
              <p>{news.description}</p>
              <Link to={`/news/${news.id}`} className="read-more-link">
                Read More
              </Link>
            </div>
          </div>
        ))}
      </div>

      {!showMore && (
        <button className="show-more-btn" onClick={handleShowMore}>
          Show More
        </button>
      )}

      {showMore && (
        <div className="news-full-page">
          {newsData.map((news) => (
            <div key={news.id} className="news-card">
              <img src={news.img} alt={news.title} />
              <div className="news-card-content">
                <h3>{news.title}</h3>
                <p>{news.description}</p>
                <Link to={`/news/${news.id}`} className="read-more-link">
                  Read More
                </Link>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default News;
